#include <bits/stdc++.h>
using namespace std;
const int N=5005;
int f[N],n,m,p;
int fa(int x)
{
	if(f[x]==x) return x;
	return f[x]=fa(f[x]);
}
void merge(int x,int y)
{
	int fx=fa(x),fy=fa(y);
	f[fx]=fy;
}
int main()
{
	cin>>n>>m>>p;
	for(int i=1;i<=n;i++) f[i]=i;
	while(m--)
	{
		int x,y;
		cin>>x>>y;
		merge(x,y);
	}
	while(p--)
	{
		int x,y;
		cin>>x>>y;
		if(fa(x)==fa(y)) cout<<"Yes\n";
		else cout<<"No\n";
	}
	return 0;
}
